#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to compute mean vector
void compute_mean_vector(double **data, int n, int p, double *mean) {
 // Initialize mean array to zeros
 for (int j = 0; j < p; j++) {
 mean[j] = 0.0;
 }

 // Sum each column
 for (int j = 0; j < p; j++) {
 for (int i = 0; i < n; i++) {
 mean[j] += data[i][j];
 }
 mean[j] /= n; // Divide by number of observations
 }
}

// Function to compute covariance matrix
void compute_covariance_matrix(double **data, int n, int p, 
 double *mean, double **cov) {
 // Initialize covariance matrix to zeros
 for (int i = 0; i < p; i++) {
 for (int j = 0; j < p; j++) {
 cov[i][j] = 0.0;
 }
 }

 // Compute covariance for each pair (i, j)
 for (int i = 0; i < p; i++) {
 for (int j = 0; j < p; j++) {
 for (int k = 0; k < n; k++) {
 double diff_i = data[k][i] - mean[i];
 double diff_j = data[k][j] - mean[j];
 cov[i][j] += diff_i * diff_j;
 }
 cov[i][j] /= (n - 1); // Sample covariance
 }
 }
}

// Function to print matrix
void print_matrix(double **matrix, int rows, int cols, char *name) {
 printf("%s:\n", name);
 for (int i = 0; i < rows; i++) {
 printf("[");
 for (int j = 0; j < cols; j++) {
 printf("%7.2f ", matrix[i][j]);
 }
 printf("]\n");
 }
}

// Function to print vector
void print_vector(double *vec, int size, char *name) {
 printf("%s:\n", name);
 printf("[");
 for (int i = 0; i < size; i++) {
 printf("%.2f ", vec[i]);
 }
 printf("]\n\n");
}

int main() {
 // Example data: 4 observations, 2 variables (X, Y)
 // X = [2, 4, 6, 8], Y = [1, 3, 4, 6]
 int n = 4; // number of observations
 int p = 2; // number of variables

 double raw_data[4][2] = {{2, 1}, {4, 3}, {6, 4}, {8, 6}};

 // Allocate memory for data pointer
 double **data = (double **)malloc(n * sizeof(double *));
 for (int i = 0; i < n; i++) {
 data[i] = raw_data[i];
 }

 // Allocate memory for mean vector
 double *mean = (double *)malloc(p * sizeof(double));

 // Allocate memory for covariance matrix
 double **cov = (double **)malloc(p * sizeof(double *));
 for (int i = 0; i < p; i++) {
 cov[i] = (double *)malloc(p * sizeof(double));
 }

 // Compute mean vector
 compute_mean_vector(data, n, p, mean);
 print_vector(mean, p, "Mean Vector (X_mean, Y_mean)");

 // Compute covariance matrix
 compute_covariance_matrix(data, n, p, mean, cov);
 print_matrix(cov, p, p, "Covariance Matrix");

 // Expected output based on manual calculation:
 // Var(X) = 20/3 = 6.67, Var(Y) = 13/3 = 4.33, Cov(X,Y) = 16/3 = 5.33
 printf("Expected: Var(X)=6.67, Var(Y)=4.33, Cov(X,Y)=5.33\n");

 // Free memory
 free(data);
 free(mean);
 for (int i = 0; i < p; i++) {
 free(cov[i]);
 }
 free(cov);

 return 0;
}

ALGORITHM ComputeMahalanobisDistance
INPUT: observation[p] - point to measure
 mean_vector[p] - center of distribution
 cov_matrix[p][p] - covariance matrix (must be invertible)
OUTPUT: distance - Mahalanobis distance from observation to mean

BEGIN
 // Step 1: Compute difference vector (observation - mean)
 FOR i = 0 TO p-1 DO
 diff[i] = observation[i] - mean_vector[i]
 END FOR

 // Step 2: Compute inverse of covariance matrix
 cov_inv = Inverse(cov_matrix) // Using Gaussian elimination or other method

 // Step 3: Compute Mahalanobis distance
 // D = sqrt(diff^T * cov_inv * diff)

 // First compute: temp = cov_inv * diff
 FOR i = 0 TO p-1 DO
 temp[i] = 0
 FOR j = 0 TO p-1 DO
 temp[i] = temp[i] + cov_inv[i][j] * diff[j]
 END FOR
 END FOR

 // Then compute: result = diff^T * temp (dot product)
 result = 0
 FOR i = 0 TO p-1 DO
 result = result + diff[i] * temp[i]
 END FOR

 distance = SquareRoot(result)

 RETURN distance
END

// Example: 2D case
// observation = [7, 5] (X=7, Y=5)
// mean = [5, 3.5]
// cov = [[6.67, 5.33], [5.33, 4.33]]
// diff = [2, 1.5]
// After computation: D ≈ 0.866

#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// For 2x2 matrix, we can compute inverse directly
// For larger matrices, use Gaussian elimination
void inverse_2x2(double matrix[2][2], double inverse[2][2]) {
 double det = matrix[0][0] * matrix[1][1] - matrix[0][1] * matrix[1][0];

 if (fabs(det) < 1e-10) {
 printf("Warning: Matrix is singular or nearly singular!\n");
 return;
 }

 double inv_det = 1.0 / det;

 // Inverse of [[a, b], [c, d]] = (1/det) * [[d, -b], [-c, a]]
 inverse[0][0] = inv_det * matrix[1][1];
 inverse[0][1] = -inv_det * matrix[0][1];
 inverse[1][0] = -inv_det * matrix[1][0];
 inverse[1][1] = inv_det * matrix[0][0];
}

double mahalanobis_distance_2d(double x[2], double mean[2], double cov[2][2]) {
 // Step 1: Compute difference vector
 double diff[2];
 diff[0] = x[0] - mean[0];
 diff[1] = x[1] - mean[1];

 // Step 2: Compute inverse of covariance matrix
 double cov_inv[2][2];
 inverse_2x2(cov, cov_inv);

 // Step 3: Compute quadratic form: diff^T * cov_inv * diff
 // temp = cov_inv * diff
 double temp[2];
 temp[0] = cov_inv[0][0] * diff[0] + cov_inv[0][1] * diff[1];
 temp[1] = cov_inv[1][0] * diff[0] + cov_inv[1][1] * diff[1];

 // result = diff^T * temp
 double quadratic_form = diff[0] * temp[0] + diff[1] * temp[1];

 // Step 4: Square root
 return sqrt(quadratic_form);
}

double euclidean_distance_2d(double x[2], double mean[2]) {
 double diff0 = x[0] - mean[0];
 double diff1 = x[1] - mean[1];
 return sqrt(diff0 * diff0 + diff1 * diff1);
}

int main() {
 // Example data: X = [2, 4, 6, 8], Y = [1, 3, 4, 6]
 // Computed earlier: mean = [5, 3.5]
 // Covariance matrix: [[6.67, 5.33], [5.33, 4.33]]

 double mean[2] = {5.0, 3.5};
 double cov[2][2] = {{6.67, 5.33}, {5.33, 4.33}};

 printf("=== Mahalanobis Distance in 2D ===\n");
 printf("Mean vector: [%.2f, %.2f]\n", mean[0], mean[1]);
 printf("Covariance matrix:\n");
 printf(" [%.2f, %.2f]\n", cov[0][0], cov[0][1]);
 printf(" [%.2f, %.2f]\n\n", cov[1][0], cov[1][1]);

 // Test points
 double test_points[3][2] = {
 {7.0, 5.0}, // Point 1
 {5.0, 3.5}, // Point 2 (at mean)
 {2.0, 1.0} // Point 3
 };

 for (int i = 0; i < 3; i++) {
 double euclidean = euclidean_distance_2d(test_points[i], mean);
 double mahalanobis = mahalanobis_distance_2d(test_points[i], mean, cov);

 printf("Test point [%d]: [%.1f, %.1f]\n", i+1, test_points[i][0], test_points[i][1]);
 printf(" Euclidean distance: %.3f\n", euclidean);
 printf(" Mahalanobis distance: %.3f\n\n", mahalanobis);
 }

 printf("Key insight: Points far along high-variance directions\n");
 printf("have smaller Mahalanobis distance than Euclidean suggests.\n");

 return 0;
}
